using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // FormatPhoneNumber tests

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("4255550199");

        Assert.StartsWith(result, "(425)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("4255550199");

        Assert.EndsWith(result, "0199");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedString()
    {
        var result = _formatter.FormatPhoneNumber("4255550199");

        Assert.AreEqual("(425) 555-0199", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException()
    {
        _formatter.FormatPhoneNumber("12345");
    }

    // BuildGreeting tests

    [TestMethod]
    public void BuildGreeting_WithName_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith(result, "Dear");
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_ReturnsExpected()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_ReturnsExpected()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith(result, "Dear Dr.");
        Assert.EndsWith(result, "Johnson,");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        _formatter.BuildGreeting("   ");
    }

    // GenerateSlug tests

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_StartsWithAlphanumeric()
    {
        var result = _formatter.GenerateSlug("  ##My Great Post!!  ");

        Assert.StartsWith(result, "my");
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_EndsWithAlphanumeric()
    {
        var result = _formatter.GenerateSlug("  ##My Great Post!!  ");

        Assert.EndsWith(result, "post");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceInput_ThrowsArgumentException()
    {
        _formatter.GenerateSlug("   ");
    }

    // FormatCurrency tests

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(9.99m, "€");

        Assert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimals()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_WithCents_ReturnsFormattedValue()
    {
        var result = _formatter.FormatCurrency(1234.56m);

        Assert.AreEqual("$1234.56", result);
    }
}

